previewCss:
.darma-loader-darma-custom-311 {
  color: var(--loader-color, #0f766e);
  height: 54px;
  aspect-ratio: 2;
  position: relative;
}
.darma-loader-darma-custom-311:before {
  content:"";
  position: absolute;
  inset: 100% 75% -3px 0;
  background: var(--loader-secondary-color, #5eead4);
  animation: darma-loader-darma-custom-311-l4-0 1s linear infinite alternate;
}
.darma-loader-darma-custom-311:after {
  content: "";
  position: absolute;
  inset: auto 42.5% 0;
  aspect-ratio: 1;
  border-radius: 50%;
  background: var(--loader-color, #0f766e);
  animation: 
    darma-loader-darma-custom-311-l4-1 1s cubic-bezier(0,700,1,700) infinite alternate,
    darma-loader-darma-custom-311-l4-2 1s linear infinite alternate;
}
@keyframes darma-loader-darma-custom-311-l4-0 {
  0%,30% {translate: 0%   -2px;rotate: 20deg}
  70%,to {translate: 300% -2px;rotate:-20deg}
}
@keyframes darma-loader-darma-custom-311-l4-1 {
  0%,2% {bottom: 0%}
  98%,to {bottom:.1%}
}
@keyframes darma-loader-darma-custom-311-l4-2 {
  0% {translate: -220%}
  to {translate:  220%}
}

